const items = $input.all();
const candidate = items[0]?.json || {};
const peers = items.slice(1).map(i => i.json).filter(p => p.peer_ticker);

let peerInfo = '';
if (peers.length > 0) {
  peerInfo = '\n\nIndustry Peers (from Neo4j graph):';
  for (const p of peers) {
    peerInfo += `\n- ${p.peer_name} (${p.peer_ticker})${p.on_watchlists?.length ? ' [on: ' + p.on_watchlists.join(', ') + ']' : ''}`;
  }
}

const d = candidate;
return [{json:{ticker:d.ticker,context:`Analyze growth stock:\nTicker: ${d.ticker} (${d.company_name})\nSector: ${d.sector} | Industry: ${d.industry} | Cap: $${(d.market_cap/1e9).toFixed(1)}B\nRevenue: $${(d.revenue/1e9).toFixed(2)}B | Growth: ${(d.revenue_growth*100).toFixed(1)}%\nEarnings Growth: ${(d.earnings_growth*100).toFixed(1)}% | P/E: ${d.pe_ratio}\nGross: ${(d.gross_margin*100).toFixed(1)}% | Op: ${(d.operating_margin*100).toFixed(1)}%\nROE: ${(d.roe*100).toFixed(1)}% | FCF: $${(d.free_cash_flow/1e9).toFixed(2)}B | D/E: ${d.debt_to_equity}${peerInfo}\nDate: ${new Date().toISOString().split('T')[0]}\n\nCompare against industry peers. Full growth analysis with score and recommendation.`}}];
